from dataclasses import dataclass
from typing import Optional
import hashlib, json

@dataclass
class PromptVersion:
    version_id: str        # e.g. "v1.4.2"
    system_prompt: str
    user_template: str     # may contain {variable} slots
    model: str
    parent_id: Optional[str] = None  # traceability to previous version

    def fingerprint(self) -> str:
        """Stable hash for dedup and audit.""\"
        payload = json.dumps({
            "system": self.system_prompt,
            "template": self.user_template,
            "model": self.model,
        }, sort_keys=True)
        return hashlib.sha256(payload.encode()).hexdigest()[:16]

class PromptRegistry:
    def __init__(self):
        self._versions: dict[str, PromptVersion] = {}
        self._active: Optional[str] = None

    def register(self, pv: PromptVersion) -> None:
        self._versions[pv.version_id] = pv

    def activate(self, version_id: str) -> None:
        if version_id not in self._versions:
            raise KeyError(f"Unknown version: {version_id}")
        self._active = version_id

    def rollback(self) -> Optional[str]:
        active = self._versions.get(self._active)
        if active and active.parent_id:
            self.activate(active.parent_id)
            return active.parent_id
        return None

    @property
    def active(self) -> Optional[PromptVersion]:
        return self._versions.get(self._active)

from dataclasses import dataclass
from typing import List

@dataclass
class EvalRun:
    version_id: str
    judge_scores: List[float]        # one per eval case
    guardrail_hit_count: int
    avg_prompt_tokens: float
    avg_completion_tokens: float

    @property
    def mean_score(self) -> float:
        return sum(self.judge_scores) / max(len(self.judge_scores), 1)

    @property
    def pass_rate(self) -> float:
        """Fraction of cases scoring >= 4 (out of 5).""\"
        return sum(1 for s in self.judge_scores if s >= 4) / max(len(self.judge_scores), 1)

@dataclass
class IterationDelta:
    version_id: str
    score_delta: float           # positive = improvement
    pass_rate_delta: float
    cost_delta_pct: float        # positive = more expensive
    guardrail_delta: int         # negative = fewer hits (good)
    promoted: bool

    @classmethod
    def compare(cls, incumbent: EvalRun, candidate: EvalRun) -> "IterationDelta":
        incum_cost = incumbent.avg_prompt_tokens + incumbent.avg_completion_tokens
        cand_cost  = candidate.avg_prompt_tokens + candidate.avg_completion_tokens
        cost_pct   = (cand_cost - incum_cost) / max(incum_cost, 1) * 100

        promoted = (
            candidate.mean_score > incumbent.mean_score + 0.05
            and candidate.pass_rate >= incumbent.pass_rate - 0.02  # allow 2 pp tolerance
            and cost_pct < 20.0
        )
        return cls(
            version_id=candidate.version_id,
            score_delta=candidate.mean_score - incumbent.mean_score,
            pass_rate_delta=candidate.pass_rate - incumbent.pass_rate,
            cost_delta_pct=cost_pct,
            guardrail_delta=candidate.guardrail_hit_count - incumbent.guardrail_hit_count,
            promoted=promoted,
        )

import difflib
from typing import List, Tuple

def prompt_diff(
    version_a: str, label_a: str,
    version_b: str, label_b: str,
) -> List[str]:
    """Returns a unified diff between two prompt versions.""\"
    lines_a = version_a.splitlines(keepends=True)
    lines_b = version_b.splitlines(keepends=True)
    return list(difflib.unified_diff(
        lines_a, lines_b,
        fromfile=label_a, tofile=label_b,
        lineterm="",
    ))

def root_cause_candidates(
    diff_lines: List[str],
    low_score_topics: List[str],   # e.g. ["refunds", "cancellation"]
) -> List[Tuple[str, str]]:
    """Heuristic: flag diff lines that mention the low-score topic keywords.""\"
    candidates = []
    for line in diff_lines:
        if not line.startswith(("+", "-")):
            continue
        for topic in low_score_topics:
            if topic.lower() in line.lower():
                candidates.append((line.strip(), topic))
    return candidates

# Example usage
diff = prompt_diff(
    "You are a helpful assistant.", "v1.2",
    "You are a helpful assistant. Never discuss refunds.", "v1.3",
)
hits = root_cause_candidates(diff, low_score_topics=["refund", "cancel"])
# hits → [('+You are a helpful assistant. Never discuss refunds.', 'refund')]
